const d = $input.first().json.body;

const esc = (v) => String(v ?? '').replaceAll('&','&amp;').replaceAll('<','&lt;').replaceAll('>','&gt;').replaceAll('"','&quot;').replaceAll("'",'&#39;');
const br  = (v) => esc(v).replace(/\n/g,'<br/>');
const euro = (v) => new Intl.NumberFormat('nl-NL',{style:'currency',currency:'EUR'}).format(Number(v??0));
const dateFmt = (v) => { try{ return new Intl.DateTimeFormat('nl-NL',{dateStyle:'long'}).format(new Date(v)); }catch(e){return String(v??'');} };

const fromName    = esc(d.from?.companyName ?? '');
const fromEmail   = esc(d.from?.email ?? '');
const fromWeb     = esc(d.from?.websiteUrl ?? '');
const fromAddr    = br(d.from?.address ?? '');
const fromVat     = esc(d.from?.vatNumber ?? '');
const fromKvk     = esc(d.from?.kvkNumber ?? '');
const fromIban    = esc(d.from?.iban ?? '');
const fromBank    = esc(d.from?.bankName ?? '');
const fromPhone   = esc(d.from?.phone ?? '');

const factuurNr   = esc(d.invoiceNumber ?? 'ONBEKEND');
const vatRate     = Number(d.vatRate ?? 21);
const subtotal    = Number(d.subtotal ?? 0);
const vatAmount   = Number(d.vatAmount ?? subtotal * vatRate / 100);
const totalAmount = Number(d.totalAmount ?? subtotal + vatAmount);
const serviceDate = dateFmt(d.serviceDate ?? d.issueDate);

const clientName    = esc(d.client?.companyName ?? '');
const clientContact = esc(d.client?.contactName ?? '');
const clientAddr    = br(d.client?.address ?? '');
const clientEmail   = esc(d.client?.email ?? '');

const html = `<!DOCTYPE html>
<html lang="nl">
<head>
<meta charset="UTF-8"/>
<style>
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
body { font-family: Arial, sans-serif; font-size: 11px; line-height: 1.55; color: #111; background: #fff; padding: 44px 52px; }

.header { display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 52px; }
.brand { font-size: 21px; font-weight: 700; color: #111; letter-spacing: -.3px; }
.brand-sub { font-size: 10px; color: #555; margin-top: 4px; }
.header-info { display: grid; grid-template-columns: auto auto; gap: 2px 28px; font-size: 10.5px; text-align: left; }
.header-info .lbl { font-weight: 700; white-space: nowrap; }
.header-info .val { color: #333; }

.recipient { margin-bottom: 36px; font-size: 11px; line-height: 1.75; }
.recipient .tav { color: #555; font-size: 10.5px; }

.doc-title { font-size: 20px; font-weight: 700; color: #111; letter-spacing: -.2px; margin-bottom: 14px; }

.meta { display: grid; grid-template-columns: auto 1fr; gap: 4px 20px; font-size: 11px; margin-bottom: 12px; }
.meta .mk { font-weight: 700; white-space: nowrap; }
.meta-line { border: none; border-top: 1px solid #bbb; margin: 20px 0; }

.items { width: 100%; border-collapse: collapse; }
.items thead tr { border-top: 1px solid #111; border-bottom: 1px solid #111; }
.items th { font-size: 10px; font-weight: 700; padding: 7px 8px; text-align: left; background: none; }
.items th.r { text-align: right; }
.items td { padding: 9px 8px; font-size: 11px; vertical-align: top; border-bottom: 1px solid #e5e5e5; }
.items td.r { text-align: right; font-variant-numeric: tabular-nums; }
.items .desc-note { font-size: 10px; color: #666; margin-top: 2px; }
.items tfoot tr { border-top: none; }
.items tfoot td { border-bottom: none; padding-top: 6px; color: #444; }

.bottom { display: flex; justify-content: space-between; align-items: flex-start; margin-top: 0; margin-bottom: 28px; }

.vat-table { border-collapse: collapse; font-size: 10px; }
.vat-table th { font-weight: 700; padding: 5px 16px 5px 0; border-bottom: 1px solid #999; text-align: left; }
.vat-table td { padding: 5px 16px 5px 0; color: #333; }

.totals { min-width: 220px; border-collapse: collapse; font-size: 11px; }
.totals td { padding: 5px 0 5px 20px; }
.totals td:last-child { text-align: right; font-variant-numeric: tabular-nums; }
.totals .sub td { color: #555; }
.totals .grand td { font-weight: 700; font-size: 12px; border-top: 1px solid #111; padding-top: 8px; }

.payment { font-size: 11px; color: #333; line-height: 1.85; border-top: 1px solid #ddd; padding-top: 16px; }

.footer { margin-top: 40px; padding-top: 10px; border-top: 1px solid #e0e0e0; font-size: 9.5px; color: #999; display: flex; justify-content: space-between; }
.footer-r { text-align: right; }
</style>
</head>
<body>

<!-- HEADER -->
<div class="header">
  <div>
    <div class="brand">${fromName}</div>
    ${fromWeb || fromEmail ? `<div class="brand-sub">${fromWeb}${fromWeb && fromEmail ? ' &middot; ' : ''}${fromEmail}</div>` : ''}
  </div>
  <div class="header-info">
    ${fromAddr ? `<span class="lbl">Adres</span><span class="val">${fromAddr}</span>` : ''}
    ${fromPhone ? `<span class="lbl">Telefoon</span><span class="val">${fromPhone}</span>` : ''}
    ${fromIban ? `<span class="lbl">IBAN</span><span class="val">${fromIban}${fromBank ? ' (' + fromBank + ')' : ''}</span>` : ''}
    ${fromKvk ? `<span class="lbl">KVK</span><span class="val">${fromKvk}</span>` : ''}
    ${fromVat ? `<span class="lbl">BTW</span><span class="val">${fromVat}</span>` : ''}
  </div>
</div>

<!-- ONTVANGER -->
<div class="recipient">
  <strong>${clientName}</strong><br/>
  ${clientContact ? `<span class="tav">T.a.v. ${clientContact}</span><br/>` : ''}
  ${clientAddr}<br/>
  ${clientEmail}
</div>

<!-- TITEL -->
<div class="doc-title">FACTUUR</div>

<!-- META -->
<div class="meta">
  <span class="mk">Factuurnummer</span><span>${factuurNr}</span>
  <span class="mk">Factuurdatum</span><span>${dateFmt(d.issueDate)}</span>
  <span class="mk">Leverdatum</span><span>${serviceDate}</span>
  <span class="mk">Vervaldatum</span><span>${dateFmt(d.dueDate)}</span>
  ${fromKvk ? `<span class="mk">KVK-nummer</span><span>${fromKvk}</span>` : ''}
</div>
<hr class="meta-line"/>

<!-- REGELITEMS -->
<table class="items">
  <thead>
    <tr>
      <th>Omschrijving</th>
      <th class="r">Aantal</th>
      <th class="r">Tarief</th>
      <th class="r">Bedrag excl. BTW</th>
    </tr>
  </thead>
  <tbody>
    ${Array.isArray(d.lineItems) && d.lineItems.length > 0
      ? d.lineItems.map(item => `<tr>
          <td>${esc(item.description ?? '')}${item.note ? `<div class="desc-note">${esc(item.note)}</div>` : ''}</td>
          <td class="r">${item.quantity != null ? esc(String(item.quantity)) + (item.unit ? ' ' + esc(item.unit) : '') : ''}</td>
          <td class="r">${item.unitPrice != null ? euro(item.unitPrice) : ''}</td>
          <td class="r">${euro(item.amount ?? item.subtotal ?? 0)}</td>
        </tr>`).join('')
      : `<tr>
          <td>${esc(d.description ?? '')}${d.project ? `<div class="desc-note">${esc(d.project.name ?? d.project)}</div>` : ''}</td>
          <td class="r">${d.quantity != null ? esc(String(d.quantity)) + (d.unit ? ' ' + esc(d.unit) : '') : ''}</td>
          <td class="r">${d.unitPrice != null ? euro(d.unitPrice) : ''}</td>
          <td class="r">${euro(subtotal)}</td>
        </tr>`
    }
  </tbody>
</table>

<!-- ONDERKANT: BTW-tabel links, totalen rechts -->
<div class="bottom">
  <table class="vat-table">
    <thead>
      <tr>
        <th>BTW-percentage</th>
        <th>Grondslag</th>
        <th>BTW-bedrag</th>
      </tr>
    </thead>
    <tbody>
      <tr>
        <td>${vatRate === 0 ? 'Vrijgesteld' : vatRate + '%'}</td>
        <td>${euro(subtotal)}</td>
        <td>${euro(vatAmount)}</td>
      </tr>
    </tbody>
  </table>

  <table class="totals">
    <tr class="sub">
      <td>Subtotaal</td>
      <td>${euro(subtotal)}</td>
    </tr>
    <tr class="sub">
      <td>BTW ${vatRate}%</td>
      <td>${euro(vatAmount)}</td>
    </tr>
    <tr class="grand">
      <td>Totaal te voldoen</td>
      <td>${euro(totalAmount)}</td>
    </tr>
  </table>
</div>

<!-- BETALING -->
<div class="payment">
  ${fromIban ? `Betaal het bedrag voor de vervaldatum op <strong>${fromIban}</strong>${fromBank ? ' t.n.v. ' + fromBank : ''} o.v.v. factuurnummer <strong>${factuurNr}</strong>.` : ''}
  ${d.notes ? `<br/><br/>${br(d.notes)}` : ''}
  ${fromEmail ? `<br/><br/>Vragen over deze factuur? Neem contact op via <strong>${fromEmail}</strong>.` : ''}
</div>

<!-- FOOTER -->
<div class="footer">
  <span>${fromName}${fromAddr ? ' &middot; ' + fromAddr.replace(/<br\/>/g,' ') : ''}</span>
  <span class="footer-r">${fromKvk ? 'KVK: ' + fromKvk + ' &middot; ' : ''}${fromVat ? 'BTW: ' + fromVat : ''}</span>
</div>

</body>
</html>`;

return [{ json: { ...d, html } }];
